value.Messages:
={{ 
($('Append or update row in sheet').item.json.Messages || '') +
"\n👤 User: " + $('WhatsApp Trigger').item.json.messages[0].text.body +
"\n🤖 AI: " + $json.output +
"\n----------------------\n"
}}

fields.fieldValue:
=

<strong>INFORMATIONS CLIENT</strong><br/>
——————————————<br/>
Date : {{ $now.format('yyyy-MM-dd | HH:mm:ss') }}<br/>
Téléphone : {{ $('WhatsApp Trigger').item.json.contacts[0].wa_id }}<br/><br/>
{{
  (() => {
    const text = $('Append or update row in sheet').item.json.Messages || '';

    const nameMatch = text.match(/Nom\s*:\s*([^|]+)/i);
    const formationMatch = text.match(/Formations?\s*:\s*([^\n]+)/i);

    const name = nameMatch ? nameMatch[1].trim() : 'Nom non renseigné';
    const formation = formationMatch ? formationMatch[1].trim() : 'Formation non renseignée';

    return `Formation : ${formation}<br/>Nom : ${name}`;
  })()
}}
<br/><br/>

<strong>HISTORIQUE DE CONVERSATION</strong><br/>
